member.example:
Bind a relay command to a TMP_InputField using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldCommandBinder _submitCommand;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Submit() { }
    }


Bind a relay command that receives the input text to a TMP_InputField by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldCommandBinder SubmitCommand => new(
            _inputField, UpdateInputFieldEvent.OnEndEdit);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Submit(string value) { }
    }

Bind a relay command to a TMP_InputField using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldCommandMonoBinder _submitCommand;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Submit() { }
        
        [RelayCommand]
        private void Submit(string text) { }
    }

Bind a relay command with one additional parameter to a TMP_InputField.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldCommandBinder<int> _searchCommand;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Search(string query, int maxResults) { }
    }

Bind a relay command with one additional parameter using a MonoBinder component.
Because InputFieldCommandMonoBinder<T> is abstract, a concrete derived class is required.

    [AddComponentMenu("MyGame/Binders/SearchCommandBinder")]
    public sealed class SearchCommandMonoBinder : InputFieldCommandMonoBinder<int> { }
    
    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SearchCommandMonoBinder _searchCommand;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Search(string query, int maxResults) { }
    }

